import { useEffect, useState } from "react";
import api from "../services/api";

function MyRegistrationsPage() {
  const [registrations, setRegistrations] = useState([]);

  const fetchRegistrations = async () => {
    try {
      const storedUser = localStorage.getItem("user");

      if (!storedUser) {
        alert("Please login first");
        return;
      }

      const user = JSON.parse(storedUser);

      const response = await api.get(`/registrations/${user.id}`);
      setRegistrations(response.data);
    } catch (error) {
      console.error("Error fetching registrations:", error);
    }
  };

  const handleCancel = async (eventId, eventTitle) => {
    try {
      const storedUser = localStorage.getItem("user");

      if (!storedUser) {
        alert("Please login first");
        return;
      }

      const user = JSON.parse(storedUser);

      const response = await api.delete("/registrations", {
        data: {
          user_id: user.id,
          event_id: eventId,
        },
      });

      alert(response.data.message || `Cancelled registration for ${eventTitle}`);
      fetchRegistrations();
    } catch (error) {
      alert(error.response?.data?.message || "Cancel failed");
      console.error("Cancel error:", error);
    }
  };

  useEffect(() => {
    fetchRegistrations();
  }, []);

  return (
    <div className="page-box">
      <h2>My Registrations</h2>
      <p>These are the events you have registered for.</p>

      {registrations.length === 0 ? (
        <p>No registrations found.</p>
      ) : (
        registrations.map((event) => (
          <div
            key={event.id}
            style={{
              border: "1px solid #ddd",
              borderRadius: "8px",
              padding: "15px",
              marginBottom: "15px",
              backgroundColor: "#fafafa",
            }}
          >
            <h3>{event.title}</h3>
            <p><strong>Description:</strong> {event.description}</p>
            <p><strong>Date:</strong> {event.event_date}</p>
            <p><strong>Location:</strong> {event.location}</p>

            <button
              style={{
                padding: "8px 16px",
                backgroundColor: "#b91c1c",
                color: "white",
                border: "none",
                borderRadius: "5px",
                cursor: "pointer",
              }}
              onClick={() => handleCancel(event.id, event.title)}
            >
              Cancel Registration
            </button>
          </div>
        ))
      )}
    </div>
  );
}

export default MyRegistrationsPage;
